// Format the already-generated leadership brief + the week's signals into a
// Slack message: macro overview, then one bullet per account with colour-coded
// signal sub-bullets, the account's WHY beneath, and the suggested move.
// Deterministic - no model call, so it can never rate-limit and always matches
// the dashboard. Nesting uses em-spaces (Slack preserves them; normal spaces collapse).
const ctx = $json.ctx || {};
const brief = ctx.brief || {};
const k = ctx.kpis || {};
const E = { risk: ':red_circle:', opportunity: ':large_green_circle:', update: ':large_blue_circle:', people: ':large_yellow_circle:' };
const IND = ' '; // em-space

const by = {};
for (const r of (ctx.by_account || [])) (by[r.account] = by[r.account] || []).push(r);
const order = Object.keys(by).sort((a, b) => {
  const ra = by[a].filter(x => x.type === 'risk').length, rb = by[b].filter(x => x.type === 'risk').length;
  return rb - ra || by[b].length - by[a].length;
});
const whyBy = {}, actBy = {};
for (const a of (brief.accounts || [])) {
  whyBy[(a.name || '').toLowerCase()] = a.why || '';
  actBy[(a.name || '').toLowerCase()] = (a.actions || [])[0] || '';
}

const wh = String(brief.whats_happening || '');
const overview = wh.split('\n').map(s => s.trim()).filter(l => l && !/^- /.test(l)).join(' ');
const points = wh.split('\n').map(s => s.trim()).filter(l => /^- /.test(l)).map(l => l.slice(2));
const headLines = [];
if (overview) headLines.push(overview);
for (const p of points.slice(0, 5)) headLines.push('•  ' + p);

const accLines = [];
for (const acc of order.slice(0, 8)) {
  const sigs = by[acc];
  const nR = sigs.filter(x => x.type === 'risk').length, nO = sigs.filter(x => x.type === 'opportunity').length;
  const rest = sigs.length - nR - nO;
  const bits = [];
  if (nR) bits.push(nR + ' risk' + (nR > 1 ? 's' : ''));
  if (nO) bits.push(nO + ' opportunit' + (nO > 1 ? 'ies' : 'y'));
  if (rest) bits.push(rest + ' update' + (rest > 1 ? 's' : ''));
  const lead = nR ? E.risk : nO ? E.opportunity : E.update;
  accLines.push(lead + '  *' + acc + '*  —  ' + bits.join(' · '));
  for (const s of sigs.slice(0, 3)) accLines.push(IND.repeat(2) + (E[s.type] || '▪️') + '  ' + s.summary + (s.band ? '  _(' + s.band + ')_' : ''));
  const why = whyBy[acc.toLowerCase()];
  if (why) accLines.push(IND.repeat(4) + '↳ _' + why + '_');
  const act = actBy[acc.toLowerCase()];
  if (act) accLines.push(IND.repeat(4) + ':arrow_right:  ' + act);
  accLines.push('');
}

// Slack caps a section at 3000 chars - chunk the account lines.
const chunks = [];
let cur = '';
for (const l of accLines) {
  if ((cur + '\n' + l).length > 2800) { chunks.push(cur); cur = l; } else cur = cur ? cur + '\n' + l : l;
}
if (cur.trim()) chunks.push(cur);

const blocks = [
  { type: 'header', text: { type: 'plain_text', text: '🧠 tnAI — the week in delivery', emoji: true } },
  { type: 'context', elements: [{ type: 'mrkdwn', text: `${k.calls || 0} calls analysed · ${k.signals || 0} signals · ${k.accounts || 0} accounts · last 7 days` }] },
];
if (headLines.length) blocks.push({ type: 'section', text: { type: 'mrkdwn', text: headLines.join('\n').slice(0, 2900) } });
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Account by account*' } });
for (const c of chunks.slice(0, 8)) blocks.push({ type: 'section', text: { type: 'mrkdwn', text: c } });
const needs = brief.needs_you || [];
if (needs.length) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':rotating_light:  *Needs you*\n' + needs.map(n => '•  ' + n).join('\n') } });
}
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: '<https://ast.tecknuovo.com|Open the dashboard>  ·  generated by tnAI from this week\'s calls, weekly reports + HubSpot' }] });

return [{ json: { payload: { text: 'tnAI — the week in delivery', blocks } } }];
